SEED_FILES[`${DEMO_PROJECT_PATH}/specs/domains/alerts/flows/send-daily-digest.yaml`] = `flow:
  id: send-daily-digest
  name: Send Daily Digest (Cron)
  type: traditional
  domain: alerts
  description: "Daily 08:00 cron job. Adds 0-5 minute random jitter via delay node to avoid thundering-herd. Reads all AlertEvents from the last 24 hours, groups by severity descending, and emails an HTML digest to the ops team. Returns 200 with digest_sent false if no alerts exist. Returns 500 on email failure."
  emits: []
  listens_to: []

trigger:
  type: cron
  event:
    schedule: "0 8 * * *"
    timezone: UTC
  job_config:
    queue: alerts
    concurrency: 1
    timeout: 600
    retry:
      max_attempts: 1

nodes:
  - id: trigger-iJ9kL3mN
    type: trigger
    label: "Cron — 08:00 UTC daily"
    position: { x: 400, y: 80 }
    config:
      schedule: "0 8 * * *"
      timezone: UTC

  - id: delay-oP4qR8sT
    type: delay
    label: "Jitter Delay (0-5 min)"
    position: { x: 400, y: 210 }
    config:
      min_ms: 0
      max_ms: 300000
      mode: random
      note: "0-5 min random jitter to avoid thundering herd — actual delay is random(0, 300000)"

  - id: collection-uV5wX9yZ
    type: collection
    label: "Filter Last 24h Alerts by Severity"
    position: { x: 400, y: 340 }
    config:
      filters:
        - field: triggered_at
          operator: gte
          value: "yesterday_start()"
          description: "Alerts from last 24 hours"
      sort:
        field: severity
        order: desc
        priority_map:
          critical: 1
          high: 2
          medium: 3
          low: 4
      group_by: severity
      show_count: true

  - id: data_store-aB2cD6eF
    type: data_store
    label: "Read AlertEvents (last 24h)"
    position: { x: 400, y: 470 }
    config:
      operation: read
      model: AlertEvent
      include:
        - rule
      query:
        triggered_at:
          gte: "yesterday_start()"
      apply_collection: true
      safety: normal

  - id: terminal-gH7iJ1kL
    type: terminal
    label: "500 DB Read Error"
    position: { x: 800, y: 470 }
    config:
      status: 500
      error_code: INTERNAL_ERROR
      body:
        error:
          code: INTERNAL_ERROR
          message: "Failed to read alert events for daily digest"
          context: "\$.error"

  - id: terminal-mN0oP4qR
    type: terminal
    label: "200 OK — No Alerts (digest skipped)"
    position: { x: 800, y: 600 }
    config:
      status: 200
      body:
        digest_sent: false
        reason: "no_alerts"
        date: "\$.digest_date"

  - id: service_call-sT3uV7wX
    type: service_call
    label: "Send Digest Email"
    position: { x: 400, y: 600 }
    config:
      method: POST
      integration: email_service
      url: /mail/send
      timeout_ms: 15000
      retry:
        attempts: 2
        backoff_ms: 2000
      request_config:
        body:
          to: "ops_team_emails"
          subject: "Daily Supply Chain Alert Digest — {{\$.digest_date}}"
          html: "\$.grouped_alerts_html"
          metadata:
            total_alerts: "\$.alert_count"
            by_severity:
              critical: "\$.grouped_alerts.critical.length"
              high: "\$.grouped_alerts.high.length"
              medium: "\$.grouped_alerts.medium.length"
              low: "\$.grouped_alerts.low.length"

  - id: terminal-yZ8aB2cD
    type: terminal
    label: "500 Email Service Error"
    position: { x: 800, y: 730 }
    config:
      status: 500
      error_code: SERVICE_UNAVAILABLE
      body:
        error:
          code: SERVICE_UNAVAILABLE
          message: "Email service unavailable — daily digest not sent"
          context: "\$.error"

  - id: terminal-eF5gH9iJ
    type: terminal
    label: "200 OK — Digest Sent"
    position: { x: 400, y: 730 }
    config:
      status: 200
      body:
        digest_sent: true
        alert_count: "\$.alert_count"
        date: "\$.digest_date"

connections:
  - from: trigger-iJ9kL3mN
    to: delay-oP4qR8sT
    sourceHandle: "default"
    data: "cron fires — apply jitter before proceeding"

  - from: delay-oP4qR8sT
    to: collection-uV5wX9yZ
    sourceHandle: "done"
    data: "jitter complete — configure collection filter"

  - from: collection-uV5wX9yZ
    to: data_store-aB2cD6eF
    sourceHandle: "valid"
    data: "24h filter, severity sort, group_by config"

  - from: data_store-aB2cD6eF
    to: terminal-gH7iJ1kL
    sourceHandle: "error"
    data: "database read error"

  - from: data_store-aB2cD6eF
    to: terminal-mN0oP4qR
    sourceHandle: "empty"
    data: "no alerts in last 24 hours"

  - from: data_store-aB2cD6eF
    to: service_call-sT3uV7wX
    sourceHandle: "success"
    data: "alert events grouped by severity for HTML digest"

  - from: service_call-sT3uV7wX
    to: terminal-yZ8aB2cD
    sourceHandle: "error"
    data: "email service call failed"

  - from: service_call-sT3uV7wX
    to: terminal-eF5gH9iJ
    sourceHandle: "success"
    data: "digest email sent successfully"

metadata:
  created: "2026-02-23T00:00:00Z"
  modified: "2026-02-23T00:00:00Z"
`;

