SEED_FILES[`${DEMO_PROJECT_PATH}/specs/domains/analytics/flows/detect-inventory-anomaly.yaml`] = `id: detect-inventory-anomaly
name: Detect Inventory Anomaly
description: "Pattern-triggered flow that fires when 3 or more stock.depleted events occur within a 60-minute rolling window for the same warehouse. Classifies severity by depletion rate, creates an AlertEvent record, and emits an alert.triggered event."
domain: analytics
type: traditional
tags: [event-driven, alerting]
criticality: high

trigger:
  type: pattern
  event:
    pattern: StockDepletedPattern
    description: "3 or more stock.depleted events within a 60-minute rolling window correlated by warehouse_id"
    source_event: stock.depleted
    correlation_key: warehouse_id
    window:
      duration: 60
      unit: minutes
    threshold:
      count: 3
      operator: gte

nodes:
  - id: trigger-aB7cF2dA
    type: trigger
    label: "Pattern — StockDepletedPattern"
    position: { x: 400, y: 80 }
    config:
      type: pattern
      pattern: StockDepletedPattern

  - id: decision-bC4dG8eB
    type: decision
    label: "Enough Correlated Events?"
    position: { x: 400, y: 210 }
    config:
      expression: "\$.correlated_events.length"
      branches:
        - condition: "\$.correlated_events.length >= 3"
          label: "true"
          target: decision-cD1eH5fC
        - condition: true
          label: "false"
          target: terminal-dE9fI3gD

  - id: terminal-dE9fI3gD
    type: terminal
    label: "200 No Anomaly"
    position: { x: 800, y: 210 }
    config:
      status: 200
      body:
        anomaly: false

  - id: decision-cD1eH5fC
    type: decision
    label: "Classify Severity by Rate"
    position: { x: 400, y: 340 }
    config:
      expression: "\$.depletion_rate"
      branches:
        - condition: "\$.depletion_rate > 5"
          label: "critical"
          description: "More than 5 depletions per hour — critical severity"
          target: data_store-eF6gJ7hE
          output:
            severity: critical
        - condition: true
          label: "high"
          description: "3-5 depletions per hour — high severity"
          target: data_store-eF6gJ7hE
          output:
            severity: high

  - id: data_store-eF6gJ7hE
    type: data_store
    label: "Create AlertEvent"
    position: { x: 400, y: 470 }
    config:
      operation: create
      model: AlertEvent
      data:
        rule_id: anomaly_rule
        type: anomaly
        severity: "\$.severity"
        context:
          warehouse_id: "\$.correlated_events[0].warehouse_id"
          sku_list: "\$.correlated_events.map(e => e.sku)"
          depletion_count: "\$.correlated_events.length"
          depletion_rate: "\$.depletion_rate"
        triggered_at: "now()"
        resolved_at: null

  - id: terminal-fG2hK9iF
    type: terminal
    label: "500 DB Write Error"
    position: { x: 800, y: 470 }
    config:
      status: 500
      error_code: INTERNAL_ERROR
      body:
        error: INTERNAL_ERROR
        message: "Failed to create alert event"

  - id: event-gH5iL4jG
    type: event
    label: "Emit alert.triggered"
    position: { x: 400, y: 600 }
    config:
      action: emit
      event: alert.triggered
      payload:
        alert_id: "\$.alert.id"
        rule_id: anomaly_rule
        type: anomaly
        severity: "\$.alert.severity"
        context: "\$.alert.context"
        triggered_at: "\$.alert.triggered_at"

  - id: terminal-hI8jM1kH
    type: terminal
    label: "200 Anomaly Detected"
    position: { x: 400, y: 730 }
    config:
      status: 200
      body:
        anomaly_detected: true
        alert_id: "\$.alert.id"

connections:
  - from: trigger-aB7cF2dA
    to: decision-bC4dG8eB
    sourceHandle: "default"
    data: "correlated event batch from pattern engine"

  - from: decision-bC4dG8eB
    to: terminal-dE9fI3gD
    sourceHandle: "false"
    data: "fewer than 3 correlated events — not an anomaly"

  - from: decision-bC4dG8eB
    to: decision-cD1eH5fC
    sourceHandle: "true"
    data: "3 or more depletions confirmed — classify severity"

  - from: decision-cD1eH5fC
    to: data_store-eF6gJ7hE
    sourceHandle: "critical"
    data: "severity=critical — depletion rate > 5/hr"

  - from: decision-cD1eH5fC
    to: data_store-eF6gJ7hE
    sourceHandle: "high"
    data: "severity=high — depletion rate between 3 and 5/hr"

  - from: data_store-eF6gJ7hE
    to: terminal-fG2hK9iF
    sourceHandle: "error"
    data: "database write failed"

  - from: data_store-eF6gJ7hE
    to: event-gH5iL4jG
    sourceHandle: "success"
    data: "persisted alert record"

  - from: event-gH5iL4jG
    to: terminal-hI8jM1kH
    sourceHandle: "emitted"
    data: "alert.triggered event emitted — return result"

metadata:
  created: "2026-02-23T00:00:00Z"
  modified: "2026-02-23T00:00:00Z"
`;

