SEED_FILES[`${DEMO_PROJECT_PATH}/specs/domains/forecasting/flows/validate-forecast-output.yaml`] = `id: validate-forecast-output
name: Validate Forecast Output
description: "Sub-flow that applies two sequential guardrail layers to an array of forecast objects: the first checks for required fields, the second checks value ranges. Used by batch-generate-forecasts and generate-ai-forecast."
domain: forecasting
type: traditional
tags: [internal, validation]
criticality: high

trigger:
  type: sub_flow
  called_by: [batch-generate-forecasts, generate-ai-forecast]
  inputs:
    forecasts:
      type: array
      required: true
      description: "Array of forecast objects to validate"
  outputs:
    valid:
      type: boolean

nodes:
  - id: guardrail-aT5uY3vK
    type: guardrail
    label: "Required Fields Check"
    position: { x: 400, y: 80 }
    config:
      checks:
        - check: "\$.forecasts.every(f => f.predicted_demand !== undefined)"
          type: required_field
          error_code: VALIDATION_ERROR
          message: "Each forecast must have a predicted_demand field"
        - check: "\$.forecasts.every(f => f.confidence !== undefined)"
          type: required_field
          error_code: VALIDATION_ERROR
          message: "Each forecast must have a confidence field"
        - check: "\$.forecasts.every(f => Array.isArray(f.daily_breakdown))"
          type: required_field
          error_code: VALIDATION_ERROR
          message: "All forecasts must have a daily_breakdown array"

  - id: terminal-bU8vZ6wL
    type: terminal
    label: "422 Required Field Missing"
    position: { x: 800, y: 80 }
    config:
      status: 422
      error_code: VALIDATION_ERROR
      body:
        error: VALIDATION_ERROR
        message: "Forecast output is missing required fields"
        context: "\$.guardrail.failed_checks"

  - id: guardrail-cV2wA9xM
    type: guardrail
    label: "Value Range Check"
    position: { x: 400, y: 210 }
    config:
      checks:
        - check: "\$.forecasts.every(f => f.confidence >= 0 && f.confidence <= 1)"
          type: range
          error_code: FORECAST_CONFIDENCE_LOW
          message: "All confidence values must be between 0 and 1"
        - check: "\$.forecasts.every(f => f.predicted_demand >= 0)"
          type: range
          error_code: INVALID_FORECAST_VALUE
          message: "All predicted_demand values must be non-negative"
        - check: "\$.forecasts.every(f => f.daily_breakdown.every(d => d.value >= 0))"
          type: range
          error_code: INVALID_FORECAST_VALUE
          message: "No daily_breakdown values may be negative"

  - id: terminal-dW5xB3yN
    type: terminal
    label: "422 Forecast Confidence Low"
    position: { x: 800, y: 210 }
    config:
      status: 422
      error_code: FORECAST_CONFIDENCE_LOW
      body:
        error: FORECAST_CONFIDENCE_LOW
        message: "Forecast values failed range validation"
        context: "\$.guardrail.failed_checks"

  - id: terminal-eX1yC7zO
    type: terminal
    label: "200 Valid"
    position: { x: 400, y: 340 }
    config:
      status: 200
      body:
        valid: true

connections:
  - from: guardrail-aT5uY3vK
    to: terminal-bU8vZ6wL
    sourceHandle: "block"
    data: "one or more required fields are absent"

  - from: guardrail-aT5uY3vK
    to: guardrail-cV2wA9xM
    sourceHandle: "pass"
    data: "all required fields present — proceed to range checks"

  - from: guardrail-cV2wA9xM
    to: terminal-dW5xB3yN
    sourceHandle: "block"
    data: "one or more values are out of valid range"

  - from: guardrail-cV2wA9xM
    to: terminal-eX1yC7zO
    sourceHandle: "pass"
    data: "all checks passed — forecasts are valid"

metadata:
  created: "2026-02-23T00:00:00Z"
  modified: "2026-02-23T00:00:00Z"
`;

SEED_FILES[`${DEMO_PROJECT_PATH}/specs/domains/inventory/domain.yaml`] = `name: Inventory
description: Stock levels, warehouse management, replenishment triggers, and IoT
  sensor monitoring
owns_schemas:
  - StockItem
  - Warehouse
flows:
  - id: list-stock-items
    name: List Stock Items
    description: Paginated stock list with collection filter, sort, deduplicate,
      aggregate by warehouse
    type: traditional
    tags:
      - public-api
    criticality: normal
    throughput: ~1000 items
  - id: get-stock-levels
    name: Get Stock Levels
    description: Stock level fetch with Redis read-through cache and cache write-back
    type: traditional
    tags:
      - public-api
    criticality: normal
  - id: adjust-stock-quantity
    name: Adjust Stock Quantity
    description: "Atomic transaction: read current, decide sufficiency, update,
      check threshold, emit stock.depleted"
    type: traditional
    tags:
      - public-api
    criticality: critical
  - id: handle-stock-depleted
    name: Handle Stock Depleted (Event)
    description: Triggered by stock.depleted — checks auto-reorder flag and calls
      procurement API
    type: traditional
    tags:
      - internal
    criticality: high
  - id: watch-warehouse-sensors
    name: Watch Warehouse Sensors (IPC)
    description: IPC-triggered sensor stream loop with anomaly detection and
      sensor.alert event
    type: traditional
    tags:
      - internal
    criticality: high
    throughput: ~500 sensor readings/min
  - id: refresh-stock-cache
    name: Refresh Stock Cache (Interval)
    description: "Every-5-min interval: filter active items, bulk read, write to
      Redis cache"
    type: traditional
    tags:
      - cron
      - internal
    criticality: normal
  - id: aaa
    name: AAA
    type: traditional
groups:
  - id: stock-ops
    name: Stock Operations
    flows: &a1
      - list-stock-items
      - get-stock-levels
      - adjust-stock-quantity
    flow_ids: *a1
  - id: automation
    name: Automation & Monitoring
    flows: &a2
      - handle-stock-depleted
      - watch-warehouse-sensors
      - refresh-stock-cache
    flow_ids: *a2
publishes_events:
  - event: stock.depleted
    from_flow: adjust-stock-quantity
    description: Stock level reached or fell below reorder threshold
    payload:
      sku: string
      warehouse_id: uuid
      quantity: number
      threshold: number
      auto_reorder: boolean
  - event: sensor.alert
    from_flow: watch-warehouse-sensors
    description: Warehouse sensor reading exceeded anomaly threshold
    payload:
      sensor_id: string
      warehouse_id: uuid
      reading: number
      threshold: number
      type: string
consumes_events:
  - event: shipment.delivered
    handled_by_flow: adjust-stock-quantity
    description: Update stock quantities when shipment is delivered
    payload:
      shipment_id: uuid
      order_id: uuid
      received_at: datetime
      lines: OrderLine[]
      carrier_id: uuid
  - event: forecast.generated
    handled_by_flow: handle-stock-depleted
    description: Update reorder thresholds based on new forecast data
    payload:
      sku: string
      warehouse_id: uuid
      forecast_horizon_days: number
      predicted_demand: number
      confidence: number
      model_version: string
on_error:
  emit_event: ErrorOccurred
layout:
  flows:
    list-stock-items:
      x: 100
      y: 100
    get-stock-levels:
      x: 100
      y: 300
    adjust-stock-quantity:
      x: 100
      y: 500
    handle-stock-depleted:
      x: 400
      y: 100
    watch-warehouse-sensors:
      x: 400
      y: 300
    refresh-stock-cache:
      x: 400
      y: 500
  portals: {}
metadata:
  created: 2026-02-23T00:00:00Z
  modified: 2026-02-23T00:00:00Z
`;

