SEED_FILES[`${DEMO_PROJECT_PATH}/specs/domains/inventory/flows/watch-warehouse-sensors.yaml`] = `flow:
  id: watch-warehouse-sensors
  name: Watch Warehouse Sensors (IPC)
  type: traditional
  domain: inventory
  description: "IPC-triggered flow that consumes a live warehouse sensor stream via a loop. Each sensor reading is evaluated against its threshold and emits sensor.alert when the reading exceeds the threshold. The loop breaks on a 'disconnect' reading type or when an unrecoverable error is encountered."
  emits: [sensor.alert]
  listens_to: []

trigger:
  type: ipc
  event:
    channel: "ipc:warehouse-sensor-stream"
    description: "Established by the desktop/gateway process when a warehouse sensor WebSocket connection is active"
    payload:
      sensor_stream:
        type: array
        description: "Async iterable of sensor reading objects"
        items:
          sensor_id: { type: string }
          warehouse_id: { type: uuid }
          value: { type: number }
          threshold: { type: number }
          type: { type: string, description: "reading type, e.g. temperature, humidity, motion, disconnect" }
          timestamp: { type: datetime }

nodes:
  - id: trigger-pQ5rS9tU
    type: trigger
    label: "IPC: ipc:warehouse-sensor-stream"
    position: { x: 400, y: 80 }
    config:
      channel: "ipc:warehouse-sensor-stream"

  - id: loop-vW2xY6zA
    type: loop
    label: "Process Sensor Stream"
    position: { x: 400, y: 210 }
    config:
      collection: "\$.sensor_stream"
      iterator: reading
      break_condition: "\$.reading.type === 'disconnect' OR \$.error !== null"
      on_error:
        action: break
        description: "Any unrecoverable stream error exits the loop cleanly"
      description: "Iterate over the live sensor reading stream until disconnect or error"

  - id: decision-bC8dE1fG
    type: decision
    label: "Reading Exceeds Threshold?"
    position: { x: 400, y: 340 }
    config:
      condition: "\$.reading.value > \$.reading.threshold"
      true_label: "anomaly"
      false_label: "normal"

  - id: event-hI3jK7lM
    type: event
    label: "Emit sensor.alert"
    position: { x: 400, y: 470 }
    config:
      operation: emit
      event: sensor.alert
      payload:
        sensor_id: "\$.reading.sensor_id"
        warehouse_id: "\$.reading.warehouse_id"
        reading: "\$.reading.value"
        threshold: "\$.reading.threshold"
        type: "\$.reading.type"
        timestamp: "\$.reading.timestamp"

  - id: terminal-nO4pQ8rS
    type: terminal
    label: "200 OK — Stream Complete"
    position: { x: 400, y: 730 }
    config:
      status: 200
      body:
        completed: true
        reason: "stream_ended"

connections:
  - from: trigger-pQ5rS9tU
    to: loop-vW2xY6zA
    sourceHandle: "default"
    data: "sensor_stream iterable"

  - from: loop-vW2xY6zA
    to: decision-bC8dE1fG
    sourceHandle: "body"
    data: "current sensor reading"

  - from: decision-bC8dE1fG
    to: event-hI3jK7lM
    sourceHandle: "true"
    data: "anomalous reading — alert required"

  - from: event-hI3jK7lM
    to: loop-vW2xY6zA
    sourceHandle: "default"
    data: "alert emitted — continue to next reading"

  - from: decision-bC8dE1fG
    to: loop-vW2xY6zA
    sourceHandle: "false"
    data: "reading within normal range — continue to next reading"

  - from: loop-vW2xY6zA
    to: terminal-nO4pQ8rS
    sourceHandle: "done"
    data: "loop exited via break_condition or stream exhausted"

metadata:
  created: "2026-02-23T00:00:00Z"
  modified: "2026-02-23T00:00:00Z"
`;

