SEED_FILES[`${DEMO_PROJECT_PATH}/specs/domains/logistics/flows/list-shipments.yaml`] = `flow:
  id: list-shipments
  name: List Shipments
  type: traditional
  domain: logistics
  description: "Paginated, filterable shipment list with collection filter on status, carrier_id, and date_range, sorted by created_at desc, left-joined with carriers table for carrier name enrichment. Returns cursor-paginated results with shaped response."
  emits: []
  listens_to: []

trigger:
  type: http
  event:
    method: GET
    path: /api/v1/shipments
    auth: jwt
    query_params:
      - name: status
        type: enum
        required: false
        values: [pending, in_transit, delivered, failed]
      - name: carrier_id
        type: uuid
        required: false
      - name: date_from
        type: string
        required: false
        description: "ISO 8601 date lower bound for created_at filter"
      - name: date_to
        type: string
        required: false
        description: "ISO 8601 date upper bound for created_at filter"
      - name: limit
        type: number
        required: false
        default: 25
        constraints:
          max: 100
      - name: cursor
        type: string
        required: false
        description: "Opaque pagination cursor from previous response"

nodes:
  - id: trigger-aB3mK7nQ
    type: trigger
    label: "GET /api/v1/shipments"
    position: { x: 400, y: 80 }
    config:
      method: GET
      path: /api/v1/shipments

  - id: collection-xR2wP9sE
    type: collection
    label: "Filter, Sort & Join Shipments"
    position: { x: 400, y: 210 }
    config:
      filter:
        status: "\$.query.status"
        carrier_id: "\$.query.carrier_id"
        created_at:
          gte: "\$.query.date_from"
          lte: "\$.query.date_to"
      sort:
        field: created_at
        direction: desc
      pagination:
        type: cursor
        limit: "\$.query.limit ?? 25"
        cursor: "\$.query.cursor"
      join:
        input: shipments
        right: carriers
        on: "carrier_id === id"
        join_type: left

  - id: data_store-hN5fT1cV
    type: data_store
    label: "Read Shipments"
    position: { x: 400, y: 340 }
    config:
      operation: read
      model: Shipment
      query: "\$.collection_query"
      include:
        - carrier
        - events
      apply_collection: true
      safety: normal

  - id: transform-qJ8dA4kZ
    type: transform
    label: "Shape Response"
    position: { x: 400, y: 470 }
    config:
      mode: expression
      output:
        data: "\$.shipments.map(s => ({ id: s.id, status: s.status, tracking_number: s.tracking_number, origin_warehouse_id: s.origin_warehouse_id, destination: s.destination, carrier: s.carrier ? { id: s.carrier.id, name: s.carrier.name } : null, event_count: s.events.length, departed_at: s.departed_at, delivered_at: s.delivered_at, eta: s.eta, created_at: s.created_at }))"
        cursor: "\$.pagination.next_cursor"
        has_more: "\$.pagination.has_more"
        total: "\$.pagination.total"

  - id: terminal-yW6mP2bR
    type: terminal
    label: "200 OK"
    position: { x: 400, y: 600 }
    config:
      status: 200
      body:
        data: "\$.output.data"
        cursor: "\$.output.cursor"
        has_more: "\$.output.has_more"
        total: "\$.output.total"

  - id: terminal-eL9kS7uF
    type: terminal
    label: "500 Internal Error"
    position: { x: 800, y: 340 }
    config:
      status: 500
      error_code: INTERNAL_ERROR
      body:
        error: INTERNAL_ERROR
        message: "An unexpected error occurred"

connections:
  - from: trigger-aB3mK7nQ
    to: collection-xR2wP9sE
    sourceHandle: "default"
    data: "query params forwarded to collection filter"

  - from: collection-xR2wP9sE
    to: data_store-hN5fT1cV
    sourceHandle: "default"
    data: "collection filter, sort, join, and pagination config applied"

  - from: data_store-hN5fT1cV
    to: transform-qJ8dA4kZ
    sourceHandle: "success"
    data: "shipment rows with carrier and events + pagination metadata"

  - from: data_store-hN5fT1cV
    to: terminal-eL9kS7uF
    sourceHandle: "error"
    data: "database error"

  - from: transform-qJ8dA4kZ
    to: terminal-yW6mP2bR
    sourceHandle: "default"
    data: "shaped paginated shipment response"

metadata:
  created: "2026-02-23T00:00:00Z"
  modified: "2026-02-23T00:00:00Z"
`;

