SEED_FILES[`${DEMO_PROJECT_PATH}/specs/domains/logistics/flows/retry-carrier-api.yaml`] = `flow:
  id: retry-carrier-api
  name: Retry Carrier API
  type: traditional
  domain: logistics
  description: "Sub-flow invoked when a carrier API call fails in route-to-carrier. Executes up to 3 retry attempts using a loop with exponential backoff delay (2^attempt * 1000ms). On each iteration a delay node pauses before the retry service_call. If any attempt succeeds the loop breaks early; if all 3 exhausted, returns 503 CARRIER_API_ERROR."
  emits: []
  listens_to: []

trigger:
  type: sub_flow
  event:
    invoked_by: route-to-carrier
    input:
      original_url: string
      original_method: string
      original_body: object

nodes:
  - id: trigger-hL3nM7pQ
    type: trigger
    label: "Sub-flow: Retry Carrier API"
    position: { x: 400, y: 80 }
    config:
      type: sub_flow

  - id: loop-iM4oN8qR
    type: loop
    label: "Retry Loop (max 3)"
    position: { x: 400, y: 210 }
    config:
      collection: [1, 2, 3]
      iterator: attempt
      break_condition: "\$.last_result.success === true || \$.attempt >= 3"

  - id: delay-jN5pO9rS
    type: delay
    label: "Exponential Backoff"
    position: { x: 400, y: 340 }
    config:
      min_ms: "Math.pow(2, \$.attempt) * 1000"
      description: "attempt 1 → 2s, attempt 2 → 4s, attempt 3 → 8s"

  - id: service_call-kO6qP1sT
    type: service_call
    label: "Retry Carrier API Call"
    position: { x: 400, y: 470 }
    config:
      method: "\$.original_method"
      integration: carrier_api
      url: "\$.original_url"
      body: "\$.original_body"
      timeout_ms: 10000

  - id: process-lP7rQ2tU
    type: process
    label: "Mark Success"
    position: { x: 400, y: 600 }
    config:
      category: data_mutation
      description: "Set \$.last_result.success = true and store response body for return after loop"
      operations:
        - set: "\$.last_result.success"
          value: true
        - set: "\$.last_result.response"
          value: "\$.service_call_response"

  - id: decision-mQ8sR3uV
    type: decision
    label: "Retry Succeeded?"
    position: { x: 400, y: 730 }
    config:
      condition: "\$.last_result.success === true"

  - id: terminal-nR9tS4vW
    type: terminal
    label: "200 OK (retry succeeded)"
    position: { x: 200, y: 860 }
    config:
      status: 200
      body: "\$.last_result.response"

  - id: terminal-oS1uT5wX
    type: terminal
    label: "503 Carrier API Error"
    position: { x: 600, y: 860 }
    config:
      status: 503
      error_code: CARRIER_API_ERROR
      body:
        error: CARRIER_API_ERROR
        message: "Carrier API failed after 3 retry attempts"

connections:
  - from: trigger-hL3nM7pQ
    to: loop-iM4oN8qR
    sourceHandle: "default"
    data: "original request params forwarded to retry loop"

  - from: loop-iM4oN8qR
    to: delay-jN5pO9rS
    sourceHandle: "body"
    data: "loop iteration start — current attempt index"

  - from: delay-jN5pO9rS
    to: service_call-kO6qP1sT
    sourceHandle: "default"
    data: "backoff elapsed — attempt carrier API call"

  - from: service_call-kO6qP1sT
    to: lP7rQ2tU
    sourceHandle: "success"
    data: "carrier API responded successfully"

  - from: service_call-kO6qP1sT
    to: loop-iM4oN8qR
    sourceHandle: "error"
    data: "carrier API failed — continue to next iteration (break_condition evaluated)"

  - from: lP7rQ2tU
    to: loop-iM4oN8qR
    sourceHandle: "default"
    data: "success flagged — loop will break on next break_condition check"

  - from: loop-iM4oN8qR
    to: decision-mQ8sR3uV
    sourceHandle: "done"
    data: "loop complete (break or max iterations exhausted)"

  - from: decision-mQ8sR3uV
    to: terminal-nR9tS4vW
    sourceHandle: "true"
    data: "at least one attempt succeeded"

  - from: decision-mQ8sR3uV
    to: terminal-oS1uT5wX
    sourceHandle: "false"
    data: "all 3 attempts failed"

metadata:
  created: "2026-02-23T00:00:00Z"
  modified: "2026-02-23T00:00:00Z"
`;

