SEED_FILES[`${DEMO_PROJECT_PATH}/specs/domains/logistics/flows/stream-shipment-position.yaml`] = `flow:
  id: stream-shipment-position
  name: Stream Shipment Position (IPC)
  type: traditional
  domain: logistics
  description: "Triggered by an IPC GPS position stream event from the Tauri desktop bridge. Loops over the incoming position stream, persisting each GPS fix as a ShipmentEvent, then broadcasting the position to all WebSocket subscribers for that shipment_id. The loop continues until a 'delivered' or 'disconnect' sentinel position is received. DB write failures are non-blocking and allow the loop to continue."
  emits: []
  listens_to: []

trigger:
  type: ipc
  event:
    channel: gps-position-stream
    bridge: tauri
    input:
      shipment_id: uuid
      position_stream: "AsyncIterator<GPSPosition>"

nodes:
  - id: trigger-pT4nM8qQ
    type: trigger
    label: "IPC: gps-position-stream"
    position: { x: 400, y: 80 }
    config:
      type: ipc
      channel: gps-position-stream
      bridge: tauri

  - id: loop-qU5oN9rR
    type: loop
    label: "Position Stream Loop"
    position: { x: 400, y: 210 }
    config:
      collection: "\$.position_stream"
      iterator: position
      break_condition: "\$.position.type === 'delivered' || \$.position.type === 'disconnect'"

  - id: data_store-rV6pO1sS
    type: data_store
    label: "Persist GPS ShipmentEvent"
    position: { x: 400, y: 340 }
    config:
      operation: create
      model: ShipmentEvent
      data:
        shipment_id: "\$.shipment_id"
        type: in_transit
        lat: "\$.position.lat"
        lng: "\$.position.lng"
        location: "\$.position.location ?? null"
        carrier_status_code: "gps_update"
        occurred_at: "now()"
      non_blocking: true

  - id: process-sW7qP2tT
    type: process
    label: "Broadcast Position via WebSocket"
    position: { x: 400, y: 470 }
    config:
      category: infrastructure
      description: "Broadcast GPS position update to all active WebSocket subscribers connected to channel shipment:{shipment_id}. Payload includes lat, lng, location, occurred_at."
      channel: "shipment:{{\$.shipment_id}}"
      payload:
        lat: "\$.position.lat"
        lng: "\$.position.lng"
        location: "\$.position.location"
        type: "\$.position.type"
        occurred_at: "now()"

  - id: terminal-tX8rQ3uU
    type: terminal
    label: "200 OK (stream ended)"
    position: { x: 400, y: 600 }
    config:
      status: 200
      body:
        stream_ended: true

connections:
  - from: trigger-pT4nM8qQ
    to: loop-qU5oN9rR
    sourceHandle: "default"
    data: "shipment_id and position_stream forwarded to loop"

  - from: loop-qU5oN9rR
    to: data_store-rV6pO1sS
    sourceHandle: "body"
    data: "current position from iterator"

  - from: data_store-rV6pO1sS
    to: process-sW7qP2tT
    sourceHandle: "success"
    data: "event persisted — broadcast position"

  - from: data_store-rV6pO1sS
    to: process-sW7qP2tT
    sourceHandle: "error"
    data: "DB write failed — non-blocking, still broadcast position"

  - from: process-sW7qP2tT
    to: loop-qU5oN9rR
    sourceHandle: "default"
    data: "position broadcast complete — continue to next iteration"

  - from: loop-qU5oN9rR
    to: terminal-tX8rQ3uU
    sourceHandle: "done"
    data: "stream ended (delivered or disconnect sentinel received)"

metadata:
  created: "2026-02-23T00:00:00Z"
  modified: "2026-02-23T00:00:00Z"
`;

