SEED_FILES[`${DEMO_PROJECT_PATH}/specs/domains/procurement/flows/bulk-approve-orders.yaml`] = `id: bulk-approve-orders
name: Bulk Approve Orders
description: "Transactional bulk approval of up to 50 orders with loop and atomic commit/rollback on error"
domain: procurement
type: traditional
tags: [public-api]
criticality: high
throughput: "~50 orders/batch"

trigger:
  type: http
  method: POST
  path: /api/v1/orders/bulk-approve
  auth: jwt
  required_roles: [procurement_manager, admin]

nodes:
  - id: input-rK7mT2bN
    type: input
    label: Validate Bulk Request
    position: { x: 400, y: 100 }
    config:
      schema:
        order_ids:
          type: array
          required: true
          min_items: 1
          max_items: 50
          items:
            type: uuid
        action:
          type: enum
          required: true
          values: [approve, reject, cancel]

  - id: terminal-cJ5wA9vP
    type: terminal
    label: 422 Validation Error
    position: { x: 800, y: 100 }
    config:
      status: 422
      body:
        error:
          code: VALIDATION_ERROR
          message: "Validation failed: {details}"
          context: "\$.validation_errors"

  - id: transaction-hF3pL6kE
    type: transaction
    label: Begin Transaction
    position: { x: 400, y: 230 }
    config:
      operation: begin
      isolation_level: read_committed
      timeout_ms: 30000

  - id: loop-qW8nS4dM
    type: loop
    label: Process Each Order
    position: { x: 400, y: 360 }
    config:
      collection: "\$.body.order_ids"
      iterator: order_id
      accumulate: results
      on_error: rollback
      max_iterations: 50

  - id: data_store-yB2mX7rT
    type: data_store
    label: Update Order Status
    position: { x: 400, y: 490 }
    config:
      operation: update
      model: PurchaseOrder
      query:
        id: "\$.order_id"
        status: submitted
        deleted_at: null
      data:
        status: "\$.body.action == 'approve' ? 'approved' : (\$.body.action == 'reject' ? 'cancelled' : 'cancelled')"
        approved_by: "\$.user_id"
        approved_at: "now()"

  - id: event-gN5kU1oW
    type: event
    label: Emit Per-Order Event
    position: { x: 400, y: 620 }
    config:
      action: emit
      event: "\$.body.action == 'approve' ? 'order.approved' : 'order.cancelled'"
      payload:
        order_id: "\$.order_id"
        action: "\$.body.action"
        approved_by: "\$.user_id"
        approved_at: "now()"

  - id: terminal-zV4aK8cQ
    type: terminal
    label: 500 Rolled Back
    position: { x: 800, y: 490 }
    config:
      status: 500
      body:
        error:
          code: INTERNAL_ERROR
          message: "An unexpected error occurred"
          context:
            partial_results: "\$.results"
            failed_order_id: "\$.order_id"
            db_error: "\$.error"

  - id: transaction-eD6fH3wJ
    type: transaction
    label: Commit Transaction
    position: { x: 400, y: 750 }
    config:
      operation: commit

  - id: terminal-oR1bP5sL
    type: terminal
    label: 200 Bulk Complete
    position: { x: 400, y: 880 }
    config:
      status: 200
      body:
        approved: "\$.results.length"
        results: "\$.results"

connections:
  - from: input-rK7mT2bN
    to: terminal-cJ5wA9vP
    sourceHandle: "invalid"

  - from: input-rK7mT2bN
    to: transaction-hF3pL6kE
    sourceHandle: "valid"

  - from: transaction-hF3pL6kE
    to: loop-qW8nS4dM
    sourceHandle: "begun"

  - from: loop-qW8nS4dM
    to: data_store-yB2mX7rT
    sourceHandle: "body"

  - from: data_store-yB2mX7rT
    to: event-gN5kU1oW
    sourceHandle: "success"

  - from: data_store-yB2mX7rT
    to: terminal-zV4aK8cQ
    sourceHandle: "error"

  - from: event-gN5kU1oW
    to: loop-qW8nS4dM
    sourceHandle: "continue"

  - from: loop-qW8nS4dM
    to: transaction-eD6fH3wJ
    sourceHandle: "done"

  - from: transaction-eD6fH3wJ
    to: terminal-oR1bP5sL
    sourceHandle: "committed"

metadata:
  created: "2026-02-23T00:00:00Z"
  modified: "2026-02-23T00:00:00Z"
`;

