SEED_FILES[`${DEMO_PROJECT_PATH}/specs/domains/procurement/flows/validate-order-safety.yaml`] = `id: validate-order-safety
name: Validate Order Safety (Sub-Flow)
description: "Reusable guardrail sub-flow: sanctioned supplier check then line total and range validation"
domain: procurement
type: traditional
tags: [internal]
criticality: critical

trigger:
  type: sub_flow
  called_by: [create-order]
  inputs:
    supplier_id:
      type: uuid
      required: true
    lines:
      type: array
      required: true
    total_amount:
      type: number
      required: true

nodes:
  - id: guardrail-pR4kX9mT
    type: guardrail
    label: Supplier Safety Checks
    position: { x: 400, y: 100 }
    config:
      position: input
      action_on_block: reject
      checks:
        - id: sanctions_check
          check: "Supplier not on OFAC or international sanctions list"
          type: external_lookup
          config:
            source: supplier_watchlist
            field: supplier_id
            lookup_value: "\$.supplier_id"
            match_action: block
          block_code: SANCTIONED_SUPPLIER
          block_message: "Cannot process order: supplier {supplier_id} is on sanctions watchlist"

        - id: supplier_status_check
          check: "Supplier status is active or onboarding"
          type: field_check
          config:
            model: Supplier
            query:
              id: "\$.supplier_id"
            field: status
            allowed_values: [active, onboarding]
            disallowed_action: block
          block_code: SUPPLIER_SUSPENDED
          block_message: "Cannot create order: supplier {supplier_id} is suspended or inactive"

  - id: terminal-bH7nM2wQ
    type: terminal
    label: 403 Blocked — Supplier Issue
    position: { x: 800, y: 100 }
    config:
      status: "\$.guardrail_block.code == 'SANCTIONED_SUPPLIER' ? 403 : 422"
      body:
        error:
          code: "\$.guardrail_block.code"
          message: "\$.guardrail_block.message"
          context:
            supplier_id: "\$.supplier_id"
            check_id: "\$.guardrail_block.check_id"

  - id: guardrail-eL5vC3jF
    type: guardrail
    label: Order Line Validation
    position: { x: 400, y: 230 }
    config:
      position: output
      action_on_block: reject
      checks:
        - id: line_total_check
          check: "Line totals sum to total_amount within 0.01 tolerance"
          type: calculation
          config:
            expression: "Math.abs(\$.lines.reduce((sum, l) => sum + (l.quantity * l.unit_price), 0) - \$.total_amount) <= 0.01"
            expected: true
            fail_action: block
          block_code: VALIDATION_ERROR
          block_message: "Validation failed: line totals do not match total_amount within 0.01 tolerance"

        - id: line_range_check
          check: "Each line quantity > 0 and unit_price > 0"
          type: range
          config:
            target: "\$.lines[*]"
            rules:
              - field: quantity
                min: 1
                inclusive: true
              - field: unit_price
                min: 0.01
                inclusive: true
            fail_action: block
          block_code: VALIDATION_ERROR
          block_message: "Validation failed: each line must have quantity >= 1 and unit_price >= 0.01"

  - id: terminal-dN8aK6oV
    type: terminal
    label: 422 Line Validation Error
    position: { x: 800, y: 230 }
    config:
      status: 422
      body:
        error:
          code: VALIDATION_ERROR
          message: "\$.guardrail_block.message"
          context:
            check_id: "\$.guardrail_block.check_id"
            details: "\$.guardrail_block.details"

  - id: terminal-zW1sP4rG
    type: terminal
    label: 200 Valid
    position: { x: 400, y: 360 }
    config:
      status: 200
      body:
        valid: true

connections:
  - from: guardrail-pR4kX9mT
    to: terminal-bH7nM2wQ
    sourceHandle: "blocked"

  - from: guardrail-pR4kX9mT
    to: guardrail-eL5vC3jF
    sourceHandle: "passed"

  - from: guardrail-eL5vC3jF
    to: terminal-dN8aK6oV
    sourceHandle: "blocked"

  - from: guardrail-eL5vC3jF
    to: terminal-zW1sP4rG
    sourceHandle: "passed"

metadata:
  created: "2026-02-23T00:00:00Z"
  modified: "2026-02-23T00:00:00Z"
`;

