SEED_FILES[`${DEMO_PROJECT_PATH}/specs/shortfalls.yaml`] = `# DDD Shortfall Report
# Generated during: /ddd-create vantage
# Date: 2026-02-23T00:00:00Z
# Purpose: Document DDD framework gaps encountered during spec design

project: vantage
generated: "2026-02-23T00:00:00Z"
ddd_version: "1.0"

# Severity: critical = blocked design intent, high = significant workaround needed,
#           medium = minor workaround, low = cosmetic or nice-to-have

missing_node_types:
  - name: websocket-broadcast
    severity: high
    description: "A node that broadcasts a payload to all WebSocket subscribers on a named channel. Distinct from the ws trigger (which receives) and service_call (which calls a remote API). Needed for server-push fan-out patterns."
    used_instead: "process node with category: infrastructure and free-text description"
    flows_affected:
      - logistics/stream-shipment-position
      - analytics/stream-live-metrics
    example_use_case: "stream-shipment-position receives GPS coordinates via IPC loop and needs to push each position update to all WebSocket clients connected to /shipments/:id/track"

inadequate_existing_nodes:
  - node_type: batch
    severity: high
    limitation: "The batch node's operation field only supports description-level specification or service_call — it cannot directly reference a sub_flow as its per-item operation. This forces complex per-item processing to be described in free text rather than as a typed sub_flow reference."
    suggestion: "Add sub_flow_ref field to batch node (alongside service_call) to allow calling a flow per item in the batch"
    flows_affected:
      - forecasting/run-daily-forecast
      - forecasting/batch-generate-forecasts

  - node_type: cache
    severity: low
    limitation: "The cache node has no ttl_jitter field for randomizing TTL within a range. Thundering herd prevention (e.g., alerts/send-daily-digest uses a delay node for jitter instead of cache-level TTL jitter) is a common cache concern."
    suggestion: "Add ttl_jitter_ms: number to cache set operation — randomizes TTL between ttl_ms and ttl_ms + ttl_jitter_ms"
    flows_affected:
      - analytics/get-dashboard-data

  - node_type: loop
    severity: medium
    limitation: "break_condition is a free-text expression string. There is no structured condition type with operators (e.g., {field: '\$.attempt', operator: 'gte', value: 3}). This makes loop termination conditions impossible to statically analyze or visualize."
    suggestion: "Support structured break_condition: {type: 'expression' | 'field_check' | 'event', field?, operator?, value?, event?} alongside the existing free-text string"
    flows_affected:
      - logistics/retry-carrier-api
      - inventory/watch-warehouse-sensors
      - logistics/stream-shipment-position

  - node_type: agent_loop
    severity: medium
    limitation: "The vector_store memory type has no schema for its configuration (embedding model, similarity threshold, namespace). The spec says 'name' and 'description' but there's no field for the embedding model, indexing strategy, or retrieval count. This makes LLM memory configuration incomplete at spec level."
    suggestion: "Add to agent_loop memory.vector_store: embedding_model, similarity_threshold, max_results, namespace fields"
    flows_affected:
      - suppliers/trigger-risk-review
      - forecasting/generate-ai-forecast

  - node_type: service_call
    severity: low
    limitation: "No fallback field for graceful degradation — when a service_call fails, the only paths are error terminal or retry sub_flow. A fallback: {value: ...} field would allow specifying a default response without routing to an error terminal, useful for non-critical enrichment calls."
    suggestion: "Add fallback: { value: any, log: boolean } to service_call — when specified, a failed call uses the fallback value instead of routing to the error handle"
    flows_affected:
      - suppliers/onboard-supplier

missing_spec_fields:
  - location: trigger
    target_type: ws
    field_name: connection_config
    severity: medium
    description: "WebSocket triggers have no configuration for authentication requirements, reconnect behavior, heartbeat interval, or max connections per client. HTTP triggers have rate_limit but ws triggers have no equivalent access control."
    workaround: "Documented in architecture.yaml cross_cutting_patterns free text; no structural enforcement"

  - location: node
    target_type: terminal
    field_name: websocket_broadcast
    severity: high
    description: "Terminals for WebSocket flows (triggered by ws trigger) need a way to push the response to all subscribed clients, not just the requesting client. Currently there's no distinction between 'respond to this client' and 'broadcast to all subscribers on this channel'."
    workaround: "Used process node before terminal to describe the broadcast behavior"

  - location: node
    target_type: event
    field_name: correlation_id
    severity: low
    description: "Event nodes have no correlation_id field for tracking related events across domain boundaries. Important for distributed tracing of supply chain events that span procurement → logistics → inventory."
    workaround: "Included correlation data in event payload as a convention"

  - location: flow
    target_type: all
    field_name: auth_required
    severity: high
    description: "Flow specs have no auth_required field or auth_scopes array to declare which roles can trigger this flow. Authentication requirements are defined in pages.yaml (UI level) but not in flow specs (API level), creating a gap between UI and API authorization documentation."
    workaround: "Documented in architecture.yaml API design section; no per-flow structural expression"

  - location: domain
    target_type: all
    field_name: sla_config
    severity: medium
    description: "Domains have no SLA configuration (max_latency_ms, alert_threshold_ms, on_breach event). The settings/handle-sla-breach flow exists but the SLA thresholds it uses are stored in SystemConfig table rather than in domain spec."
    workaround: "SLA thresholds stored in SystemConfig database table; referenced by handle-sla-breach flow"

connection_limitations:
  - severity: medium
    limitation: "circuit_break behavior is supported as a connection behavior value but has no configuration fields (failure_threshold, recovery_timeout, half_open_max_calls). Using circuit_break is effectively a placeholder label without any structural specification."
    context: "logistics/retry-carrier-api uses exponential delay loop as workaround instead of structural circuit breaker"
    suggestion: "Add circuit_break_config: { failure_threshold: number, recovery_timeout_ms: number, half_open_max_calls: number } to connections that use behavior: circuit_break"

  - severity: low
    limitation: "Cannot express a 'fan-in' join pattern — waiting for multiple independent event nodes to complete before proceeding. Parallel node branches all proceed independently; there is no 'wait for all these events to arrive' gate beyond the human_gate node."
    context: "alerts/handle-supply-chain-event consumes a composite event_group but the correlation logic (match by sku_id or order_id across events) cannot be expressed structurally"
    suggestion: "Add a correlation_gate node type or extend event_group trigger with correlation_key field"

layer_gaps:
  l1_system:
    elements_used: ["zones", "domain blocks", "data_flow arrows", "pipeline chains", "schedule badges", "integration blocks"]
    missing_elements:
      - description: "WebSocket connection topology — which domains/flows serve WebSocket endpoints and which clients connect to them — is not visible at L1. The Socket.io realtime layer is invisible."
        severity: medium
        example: "logistics/stream-shipment-position and analytics/stream-live-metrics serve WebSocket connections but their clients (frontend pages) and connection patterns aren't visible at L1"
      - description: "BullMQ queue topology — which flows produce jobs to which queues, and which workers consume which queues — is not visible at L1. The queue-worker service appears as a single block with no queue-level breakdown."
        severity: medium
        example: "forecasting/run-daily-forecast produces jobs to the 'forecasting' queue; analytics/generate-weekly-report produces to 'reports' queue — this routing is invisible"
    invisible_information:
      - description: "Per-service memory and CPU resource annotations (e.g., the AI agent loops and batch forecasting are computationally expensive)"
        should_be_visible: true
        reason: "Helps architects identify performance bottlenecks and infrastructure sizing requirements during design"
      - description: "API rate limit annotations per integration (requests_per_second)"
        should_be_visible: false
        reason: "Too granular for L1; belongs in integration config detail view"

  l2_domain:
    elements_used: ["flow blocks", "flow groups", "event arrows", "orchestration arrows", "throughput badges", "criticality badges"]
    missing_elements:
      - description: "Agent memory topology at L2 — when a domain has agent flows using vector_store, key_value, or conversation_history, the memory stores they use are not shown as domain-level components alongside database and cache stores"
        severity: medium
        example: "suppliers domain uses vector_store 'supplier-research' in trigger-risk-review but this store isn't visualized alongside the domain's data relationships"
      - description: "BullMQ queue membership — cron/interval flows that run via queue-worker should show which queue they belong to at L2"
        severity: low
        example: "forecasting/run-daily-forecast runs in the 'forecasting' queue with concurrency: 1 but this isn't visible at L2 level"
    invisible_information:
      - description: "Aggregate throughput: total requests/day across all flows in a domain"
        should_be_visible: true
        reason: "Helps identify high-load domains that need infrastructure scaling attention"

  l3_flow:
    elements_used: ["all 28 node types", "trigger, input, process, decision, terminal, data_store, service_call, ipc_call, event, loop, parallel, sub_flow, llm_call, delay, cache, transform, collection, parse, crypto, batch, transaction, agent_loop, guardrail, human_gate, orchestrator, smart_router, handoff, agent_group"]
    missing_elements:
      - description: "WebSocket fan-out visualization: when a process node broadcasts to N connected clients, the fan-out factor (N clients) is not expressible as a visual element on the flow canvas"
        severity: medium
        example: "analytics/stream-live-metrics needs to show '→ broadcast to N WebSocket clients' but can only show a process node with free-text description"
    invisible_information:
      - description: "LLM token consumption estimates per llm_call node (prompt tokens + max_tokens × requests)"
        should_be_visible: true
        reason: "Helps estimate API costs during design; LLM calls are expensive and knowing per-flow cost impact is valuable"
      - description: "Batch processing progress — when batch nodes run, intermediate progress (X/N complete) is not capturable in the spec"
        should_be_visible: false
        reason: "Runtime concern; appropriate for monitoring dashboard, not design-time spec"

workarounds:
  - flow: logistics/stream-shipment-position
    node_id: process-ws01cast
    node_type_used: process
    intended_operation: "Broadcast GPS position update to all WebSocket clients subscribed to /shipments/:id/track channel"
    why_no_fit: "No structured node type for WebSocket server-push broadcast. service_call targets an external HTTP endpoint. event emits to the domain event bus. Neither models 'push to all Socket.io room members'."
    proposed_node_type: "websocket-broadcast (new): {channel: string, event_name: string, payload: expression}"
    severity: high

  - flow: analytics/stream-live-metrics
    node_id: process-lm02cast
    node_type_used: process
    intended_operation: "Broadcast aggregated real-time metrics to all connected analytics dashboard WebSocket clients"
    why_no_fit: "Same as above — no structured node type for Socket.io room broadcast"
    proposed_node_type: "websocket-broadcast (new): {channel: string, event_name: string, payload: expression}"
    severity: high

cross_cutting_gaps:
  - concern: auth
    severity: high
    description: "JWT authentication middleware is applied to all HTTP-triggered flows (except register and login) but cannot be expressed structurally in DDD. The auth requirement exists at the flow level but can only be documented in architecture.yaml free text and pages.yaml auth_required flag."
    current_expression: "Documented in architecture.yaml API design section as a convention; pages.yaml has auth_required per page; no per-flow auth declaration exists"
    suggestion: "Add auth field to flow metadata: {required: boolean, roles: string[], strategy: 'jwt' | 'api_key' | 'any'} — then /ddd-implement generates auth middleware accordingly"

  - concern: rate_limiting
    severity: medium
    description: "The rate_limit field on HTTP triggers specifies per-endpoint limits but there is no domain-level rate limit or user-tier rate limit expressible structurally. Vantage needs different limits for admin (high) vs. viewer (low) roles."
    current_expression: "Single rate_limit per trigger; role-based limits not expressible"
    suggestion: "Extend trigger rate_limit to support tier_limits: [{ role: string, max_requests: number, window_ms: number }]"

  - concern: logging
    severity: low
    description: "Structured logging (what fields to log at each node, log levels per node) has no first-class representation. All flows log uniformly via Pino but specific business events (order approved, supplier flagged) that should be logged with structured context cannot be declared at spec level."
    current_expression: "Mentioned in architecture.yaml; no per-node or per-flow logging configuration"
    suggestion: "Add optional log field to nodes: { level: 'info' | 'warn' | 'error', fields: string[], condition: expression? } — emits a structured log entry at that point in the flow"

  - concern: monitoring
    severity: low
    description: "No structured way to declare which flows emit custom Prometheus metrics or what metric names/labels to use. The analytics/get-dashboard-data flow is performance-critical but there's no spec-level declaration for custom instrumentation."
    current_expression: "Not expressible; monitoring setup is purely implementation concern"
    suggestion: "Add optional metrics field to flow metadata: [{name: string, type: counter|gauge|histogram, labels: string[]}] — /ddd-scaffold generates metric registration code"

ui_shortfalls:
  missing_component_types:
    - name: map-view
      severity: high
      description: "An interactive map component for displaying GPS coordinates with real-time marker updates, route paths, and geographic clustering. Essential for logistics and supply chain visibility."
      used_instead: "chart component with chart_type: map (a stretch of the chart component's intended purpose — chart is for data visualization, not geographic mapping)"
      pages_affected:
        - shipment-tracking
      example_use_case: "shipment-tracking needs a live GPS map showing current carrier position, route history, and destination — not a chart"

    - name: timeline
      severity: medium
      description: "A vertical timeline component for displaying ordered events with timestamps, icons, and status indicators. Distinct from item-list which is a flat list without temporal flow visualization."
      used_instead: "item-list component (loses the visual temporal relationship between events)"
      pages_affected:
        - shipment-tracking
        - supplier-detail
      example_use_case: "shipment-tracking event timeline (departed → in_transit → out_for_delivery → delivered) needs visual step indicators and time gaps between events, not just a flat list"

  inadequate_components:
    - component: chart
      severity: high
      limitation: "chart_type: map is used as a workaround for geographic data but the chart component has no fields for map-specific configuration: center coordinates, zoom level, marker configuration, route polylines, or real-time position updates. Using chart for a geographic map conflates two very different visualization paradigms."
      suggestion: "Either add a dedicated map-view component type, or add a map_config: {center_lat, center_lng, zoom, markers[], routes[], realtime_marker?} sub-spec to the chart component when chart_type: map"
      pages_affected:
        - shipment-tracking

    - component: item-list
      severity: medium
      limitation: "item-list with virtual_scroll cannot express real-time item prepending (new items arriving at the top of the list via WebSocket push). The realtime state subscription pushes new data but the list doesn't have an insert_position: top | bottom config for realtime updates."
      suggestion: "Add realtime_insert_position: 'top' | 'bottom' to item-list sections that have both virtual_scroll and a realtime data source"
      pages_affected:
        - shipment-tracking
        - analytics

  form_limitations:
    - severity: high
      limitation: "Repeating field groups (sub-tables) within a form cannot be expressed. The create-edit-order page needs order lines — a dynamic list of {sku, description, quantity, unit_price} rows — as a form sub-component. This is a very common form pattern (invoice lines, order items, BOM rows) with no spec representation."
      context: "create-edit-order needs an order lines sub-table with inline-edit, add row, delete row. Workaround: textarea with JSON, which loses all type safety and UX quality."
      suggestion: "Add repeating_group form field type: {name, columns: [{name, type, label, required}], min_rows, max_rows, add_label, remove_label} — renders as an editable grid with add/remove row controls"

    - severity: medium
      limitation: "Form fields have no depends_on / visible_when cross-field conditional logic that updates options dynamically. The supplier_id field in create-edit-order should filter the currency dropdown based on selected supplier's preferred currency, but this dynamic dependency can't be expressed."
      context: "create-edit-order supplier → currency dependency; onboard-supplier country → currency recommendation"
      suggestion: "Extend form field with options_depends_on: {field: string, transform: 'filter' | 'set_default' | 'set_options'} for dynamic option updates based on sibling field values"

  interaction_gaps:
    - pattern: multi-step-wizard
      severity: medium
      description: "The supplier onboarding form (12 fields across basic info, capabilities, and contract terms) would benefit from a guided multi-step wizard with progress indicator and per-step validation. There is no multi-step-wizard interaction pattern in the spec."
      pages_affected:
        - onboard-supplier
      suggestion: "Add wizard form type: {steps: [{id, title, description, fields: string[]}], show_progress: boolean, allow_skip: boolean} — renders as a tabbed/stepped form with Next/Back navigation and per-step validation"

    - pattern: real-time-list-update
      severity: medium
      description: "There is no interaction pattern for real-time item updates in lists (row highlight on update, smooth item insertion, status badge animation on WebSocket push). The realtime field on page state indicates a subscription but there's no spec for how the UI should react to incoming data."
      pages_affected:
        - shipments
        - dashboard
        - analytics
      suggestion: "Add realtime_behavior: {on_new_item: 'prepend' | 'append' | 'refresh', on_update: 'highlight' | 'silent' | 'badge_count', highlight_duration_ms: number} to sections with realtime data sources"

pillar_balance:
  logic_flows: 52
  data_schemas: 17
  ui_pages: 12
  infrastructure_services: 7
  product_described_pages:
    - "Dashboard (/): described in Interface Pillar §1"
    - "Suppliers List (/suppliers): described in Interface Pillar §2"
    - "Supplier Detail (/suppliers/:id): described in Interface Pillar §3"
    - "Onboard Supplier (/suppliers/new): described in Interface Pillar §4"
    - "Purchase Orders (/orders): described in Interface Pillar §5"
    - "Create/Edit Purchase Order (/orders/new, /orders/:id/edit): described in Interface Pillar §6"
    - "Inventory (/inventory): described in Interface Pillar §7"
    - "Warehouse Map (/warehouses): described in Interface Pillar §8"
    - "Shipments (/shipments): described in Interface Pillar §9"
    - "Live Shipment Tracking (/shipments/:id/track): described in Interface Pillar §10"
    - "Forecasts (/forecasts): described in Interface Pillar §11"
    - "Analytics (/analytics): described in Interface Pillar §12"
  pages_without_specs: []
  imbalance_warnings: []

summary:
  total_shortfalls: 26
  by_severity:
    critical: 0
    high: 9
    medium: 11
    low: 6
  feature_coverage:
    node_types: "28/28"
    trigger_types: "10/13"
    collection_operations: "11/11"
    crypto_operations: "5/6"
    parse_formats: "2/7"
    data_store_types: "2/3"
    connection_behaviors: "2/4"
    ui_component_types: "9/9"
    form_field_types: "14/14"
    schema_index_types: "3/4"
    schema_seed_strategies: "2/3"
    schema_relationship_types: "4/4"
    infrastructure_service_types: "4/4"
    orchestrator_strategies: "4/4"
    handoff_modes: "3/3"

    unused_but_applicable:
      - feature: "trigger: sse"
        could_replace: "The analytics live metrics endpoint could use SSE instead of WebSocket for one-directional server-push (analytics/stream-live-metrics)"
        reason: "SSE is simpler than WebSocket for server→client only push; analytics dashboard doesn't need bidirectional communication"
      - feature: "trigger: shortcut"
        could_replace: "keyboard shortcuts defined in pages.yaml could alternatively be expressed as shortcut-triggered flows in domain specs"
        reason: "Command palette actions (Cmd+N → new PO) are currently only in pages.yaml; they could trigger procurement/create-order via shortcut trigger"
      - feature: "data_store: filesystem"
        could_replace: "procurement/create-order and suppliers/onboard-supplier file attachment handling currently uses service_call to MinIO S3 API"
        reason: "In development, a filesystem data_store could handle attachment storage without MinIO, simplifying local dev setup"
      - feature: "parse: rss, atom, html, csv, markdown"
        could_replace: "Not applicable — no RSS/Atom feeds, web scraping, CSV imports, or markdown parsing needed in this project"
        reason: "Vantage is a B2B ops platform using EDI (XML) and carrier JSON webhooks; content parsing formats not needed"
      - feature: "schema seed strategy: script"
        could_replace: "AlertRule seed currently uses fixture strategy"
        reason: "migration strategy would be more appropriate for the 3 default AlertRule records since they're immutable system data, not dev fixtures"
      - feature: "connection behavior: stop, retry"
        could_replace: "Multiple flows use sub_flow retry loops where connection behavior: retry could be simpler"
        reason: "logistics/retry-carrier-api is an entire sub_flow for retry logic that could be replaced by behavior: retry with a retry_config on the service_call error connection"

  top_recommendation: "Add a websocket-broadcast node type — the single most impactful gap found in this project. Two flows require process nodes as workarounds (stream-shipment-position, stream-live-metrics), and the absence of this node means WebSocket server-push logic is invisible on the flow canvas, breaking the visual completeness promise of DDD for realtime applications."
`;

